mapper.select:
select

from wings_student


        student_no = #{studentNo,jdbcType=VARCHAR}


        and student_name = #{studentName,jdbcType=VARCHAR}


        and id_no = #{idNo,jdbcType=VARCHAR}


        and academy = #{academy,jdbcType=VARCHAR}


        and campus = #{campus,jdbcType=VARCHAR}


        and major = #{major,jdbcType=VARCHAR}


        and poor_level = #{poorLevel,jdbcType=VARCHAR}


        and sex = #{sex,jdbcType=VARCHAR}


        and class_name = #{className,jdbcType=VARCHAR}


        and nation = #{nation,jdbcType=VARCHAR}


        and phone = #{phone,jdbcType=VARCHAR}


        and email = #{email,jdbcType=VARCHAR}


        and qq = #{qq,jdbcType=VARCHAR}
